import{_ as i,o as t,c as a,a2 as r}from"./chunks/framework.DIMps2S2.js";const g=JSON.parse('{"title":"股票转仓","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/stock-transfer/hk-transfer.md","filePath":"zh-CN/stock-trading/stock-transfer/hk-transfer.md"}'),e={name:"stock-trading/stock-transfer/hk-transfer.md"};function o(n,l,s,d,h,p){return t(),a("div",null,[...l[0]||(l[0]=[r('<h1 id="股票转仓" tabindex="-1">股票转仓 <a class="header-anchor" href="#股票转仓" aria-label="Permalink to &quot;股票转仓&quot;">​</a></h1><p>将在其他券商持有的股票转移至长桥账户（转入），或从长桥转至其他券商（转出）。仅支持本人同名账户间转仓。</p><h2 id="支持品类与收费" tabindex="-1">支持品类与收费 <a class="header-anchor" href="#支持品类与收费" aria-label="Permalink to &quot;支持品类与收费&quot;">​</a></h2><table tabindex="0"><thead><tr><th>账户</th><th>支持市场</th><th>转出收费</th></tr></thead><tbody><tr><td>香港综合账户</td><td>港股（股票/ETF）、美股（股票/ETF）</td><td>港股 500 HKD/次；美股 150 USD/次</td></tr><tr><td>新加坡综合账户</td><td>港股（股票/ETF）、美股（股票/ETF）、新加坡股票</td><td>以官网为准，另加 9% GST（如适用）</td></tr></tbody></table><p>转入长桥不收费；转出前请确保账户内有足够手续费，转出券商可能另行收费，请与对方确认。</p><h2 id="处理时间" tabindex="-1">处理时间 <a class="header-anchor" href="#处理时间" aria-label="Permalink to &quot;处理时间&quot;">​</a></h2><p>转入：转仓指示确认后 3–5 个工作日<br> 转出：5–10 个工作日（以双方券商实际处理时间为准）</p><hr><h2 id="香港账户" tabindex="-1">香港账户 <a class="header-anchor" href="#香港账户" aria-label="Permalink to &quot;香港账户&quot;">​</a></h2><h3 id="转入股票" tabindex="-1">转入股票 <a class="header-anchor" href="#转入股票" aria-label="Permalink to &quot;转入股票&quot;">​</a></h3><p><strong>接收方信息（提供给转出券商）：</strong></p><p>港股：</p><ul><li>接收券商：长桥证券（香港）有限公司 Long Bridge HK Limited</li><li>CCASS 代码：B02195</li><li>接收账户：您的长桥证券账户号码</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk</li></ul><p>美股：</p><ul><li>接收券商：Long Bridge HK Limited</li><li>DTC 代码：DTC 0534</li><li>接收账户：您的长桥证券账户号码（若格式受限，填写 U11928885）</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk</li></ul><p><strong>操作流程：</strong></p><ol><li>长桥 App → 资产 → 存入股票 → 提交转入申请</li><li>选择转出券商，填写信息，添加股票代码及数量</li><li>确认后提交，转仓指引发送至注册邮箱</li><li>按邮件下载申请表，打印签名后发至转出券商申请转出</li><li>等待双方券商确认后完成转移</li></ol><p><strong>成本价说明：</strong> 每股成本价为选填项。未填写时按转仓成功当日收盘价计算；已填写后无法修改，如有疑问请联系客服。</p><p>各券商转入长桥的详细操作指引请参考<a href="/wiki/stock-trading/stock-transfer/broker-transfer-guide">其他券商转入</a>。</p><h3 id="转出股票" tabindex="-1">转出股票 <a class="header-anchor" href="#转出股票" aria-label="Permalink to &quot;转出股票&quot;">​</a></h3><p><strong>长桥转出方信息（提供给接收券商）：</strong></p><p>港股：</p><ul><li>转出券商：长桥证券（香港）有限公司 Long Bridge HK Limited</li><li>CCASS 代码：B02195</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk</li></ul><p>美股：</p><ul><li>转出券商：Long Bridge HK Limited</li><li>DTC 代码：DTC 0534</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk</li></ul><p><strong>操作流程：</strong></p><ol><li>长桥 App → 资产 → 全部功能 → 转出股票 → 提交转出申请</li><li>填写接收券商信息、账户姓名和账户号码</li><li>填写股票信息，确认后提交</li><li>可在转出记录中查看处理进度</li></ol><p><strong>Interactive Brokers（盈透）：</strong> 需在 IB 端提交申请后联系长桥客服提供转仓订单编号（Reference Number）。填写接收账户时请填写长桥 H 开头的证券账号，不要填写 UID。</p><hr><h2 id="新加坡账户" tabindex="-1">新加坡账户 <a class="header-anchor" href="#新加坡账户" aria-label="Permalink to &quot;新加坡账户&quot;">​</a></h2><h3 id="转入股票-1" tabindex="-1">转入股票 <a class="header-anchor" href="#转入股票-1" aria-label="Permalink to &quot;转入股票&quot;">​</a></h3><ol><li>长桥 App → 资产 → 全部功能 → 存入股票 → 提交股票转入申请</li><li>填写转出券商、股票代码和转入数量</li><li>确认后提交，注册邮箱将收到具体指引</li><li>联系转出券商告知转仓，确认后点击「已联系」</li></ol><p><strong>成本价说明：</strong> 与香港账户相同，选填；未填写时按转仓成功当日收盘价计算。</p><h3 id="转出股票-1" tabindex="-1">转出股票 <a class="header-anchor" href="#转出股票-1" aria-label="Permalink to &quot;转出股票&quot;">​</a></h3><ol><li>长桥 App → 资产 → 全部功能 → 转出股票 → 提交股票转出申请</li><li>填写接收券商信息和股票信息后提交</li><li>通知接收券商通过邮件/电话与长桥确认指示与交割时间</li><li>双方券商收到相同指示后完成转仓</li></ol><p><strong>转出 OTC 股票：</strong> App 内不支持，需发送申请至 <a href="mailto:contact@longbridge.sg" target="_blank" rel="noreferrer">contact@longbridge.sg</a>，同时向接收券商提交股票转入指令。</p><p><strong>Interactive Brokers（盈透）：</strong> 需在 IB 端提交申请后联系长桥客服提供转仓订单编号。填写接收账户时请填写长桥 SG 开头的证券账号，不要填写 UID。</p><hr><h2 id="通用限制与派息处理" tabindex="-1">通用限制与派息处理 <a class="header-anchor" href="#通用限制与派息处理" aria-label="Permalink to &quot;通用限制与派息处理&quot;">​</a></h2><ul><li>仅支持本人同名账户间转仓（新加坡账户仅支持 NCBO，暂不支持变更受益人转仓）</li><li>只有「待提交」状态的申请才能修改，「执行中」状态需重新提交</li><li>取消转仓申请需双方券商同时取消</li><li>持仓股票需结算完成才可提交转出</li><li>新加坡账户处于融资中或手续费不足时无法发起转出</li><li>转仓过程中如遇股票派息，长桥收到后会入账至客户长桥账户</li><li>如无法在 App 内操作，可通过邮件申请：<a href="https://pub.lbkrs.com/files/202602/rdnfx1shWbkNDAwD/___20260206.pdf" target="_blank" rel="noreferrer">下载转仓表格</a></li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/stock-transfer">股票转仓</a></li></ul>',42)])])}const u=i(e,[["render",o]]);export{g as __pageData,u as default};
